using sv_c0a9c9d97d3e41d4918d783b36757b1e.Models;

namespace sv_c0a9c9d97d3e41d4918d783b36757b1e.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, guanciale, and pecorino.", 25),
            new(2, "Margherita Pizza", "Simple pizza with tomato, mozzarella, and fresh basil.", 45),
            new(3, "Tiramisu", "Coffee-flavoured layered dessert with mascarpone cream.", 30),
            new(4, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 35),
        },
        [2] = new List<Recipe>
        {
            new(5, "Chicken Tikka Masala", "Tender chicken in a creamy spiced tomato sauce.", 40),
            new(6, "Palak Paneer", "Fresh spinach cooked with soft paneer cubes and spices.", 30),
            new(7, "Biryani", "Fragrant layered rice dish with meat and aromatic spices.", 60),
            new(8, "Samosa", "Crispy pastry filled with spiced potatoes and peas.", 50),
        },
        [3] = new List<Recipe>
        {
            new(9, "Sushi Rolls", "Vinegared rice with fresh fish wrapped in nori.", 45),
            new(10, "Ramen", "Rich broth with wheat noodles, pork, and soft-boiled egg.", 120),
            new(11, "Tempura", "Lightly battered and deep-fried seafood and vegetables.", 25),
            new(12, "Miso Soup", "Traditional soup with dashi broth, tofu, and seaweed.", 15),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_c0a9c9d97d3e41d4918d783b36757b1e.Models
@using sv_c0a9c9d97d3e41d4918d783b36757b1e.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null && _isLoading)
{
    <p><em>Loading recipes...</em></p>
}
else if (_recipes is not null)
{
    @if (_isLoading)
    {
        <p><em>Refreshing…</em></p>
    }

    <div>
        @foreach (var recipe in GetSortedRecipes())
        {
            <div class="card mb-3">
                <div class="card-body">
                    <h5 class="card-title">@recipe.Title</h5>
                    <p class="card-text">@recipe.Description</p>
                    <span class="badge bg-secondary">Prep: @recipe.PrepTimeMinutes min</span>
                </div>
            </div>
        }
    </div>
}
else
{
    <p>No recipes found for this cuisine.</p>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isLoading;
    private string? _error;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only sort changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request for a previous cuisine.
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var cancellationToken = _cts.Token;

        _isLoading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cancellationToken);

            if (cancellationToken.IsCancellationRequested)
            {
                return;
            }

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _error = null;
        }
        catch (OperationCanceledException)
        {
            // Request was intentionally cancelled — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isLoading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private List<Recipe> GetSortedRecipes()
    {
        if (_recipes is null)
        {
            return new List<Recipe>();
        }

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id).ToList(),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes).ToList(),
            _ => _recipes,
        };
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

